<script>
/* ────────────────────────────────────────────
    DATA INTERACTION FROM WEBHOOK
──────────────────────────────────────────── */
const RAW_DATA = {{ JSON.stringify($input.all().map(i => i.json)) }};

/* ────────────────────────────────────────────
    TEAM CONFIGURATION MAP
──────────────────────────────────────────── */
// TODO: Replace with actual team assignments
const TEAM_MAP = {
  'team member 1': 'Team A',
  'team member 2': 'Team A',
  'team member 3': 'Team B',
  'team member 4': 'Team B'
};

function getTeamName(username) {
  const cleanName = (username || '').toLowerCase().trim();
  return TEAM_MAP[cleanName] || 'E';
}

/* ────────────────────────────────────────────
    DYNAMIC AESTHETIC / PILL GENERATOR
──────────────────────────────────────────── */
function getStatusConfig(rawStatus) {
  const label = (rawStatus || 'Not Started').trim();
  const key = label.toLowerCase().replace(/[^a-z0-9]/g, '');
  const lo = label.toLowerCase();

  if (lo.includes('block')) {
    return { key, label, isBlocking: true, isEscalated: false, styles: `background:rgba(249,115,22,0.14); color:#fb923c; border:1px solid rgba(249,115,22,0.28);` };
  }
  if (lo.includes('escalat') || lo.includes('crit')) {
    return { key, label, isBlocking: false, isEscalated: true, styles: `background:rgba(239,68,68,0.14); color:#f87171; border:1px solid rgba(239,68,68,0.28);` };
  }
  if (lo.includes('work') || lo.includes('progress') || lo.includes('done') || lo.includes('complet')) {
    return { key, label, isBlocking: false, isEscalated: false, styles: `background:rgba(16,185,129,0.12); color:#34d399; border:1px solid rgba(16,185,129,0.25);` };
  }
  if (lo.includes('not') || lo.includes('start') || lo.includes('queue')) {
    return { key, label, isBlocking: false, isEscalated: false, styles: `background:rgba(100,116,139,0.14); color:#94a3b8; border:1px solid rgba(100,116,139,0.22);` };
  }

  let hash = 0;
  for (let i = 0; i < label.length; i++) hash = label.charCodeAt(i) + ((hash << 5) - hash);
  const hue = Math.abs(hash) % 360;
  return {
    key,
    label,
    isBlocking: false,
    isEscalated: false,
    styles: `background:hsla(${hue}, 45%, 50%, 0.12); color:hsl(${hue}, 70%, 72%); border:1px solid hsla(${hue}, 45%, 50%, 0.25);`
  };
}

/* ────────────────────────────────────────────
    THEME
──────────────────────────────────────────── */
let isDark = true;
const themeIcon = document.getElementById('themeIcon');
function applyTheme(dark) {
  isDark = dark;
  document.documentElement.dataset.theme = dark ? 'dark' : 'light';
  themeIcon.className = dark ? 'fa-solid fa-sun' : 'fa-solid fa-moon';
  document.getElementById('themeToggle').style.color = dark ? '#fbbf24' : '#8b5cf6';
}
applyTheme(true);
document.getElementById('themeToggle').addEventListener('click', () => applyTheme(!isDark));

/* ────────────────────────────────────────────
    DATE PARSING
──────────────────────────────────────────── */
const urlParams = new URLSearchParams(window.location.search);
let reportDate = urlParams.get('date');
if (!reportDate) {
  const t  = new Date();
  const dd = String(t.getDate()).padStart(2,'0');
  const mm = String(t.getMonth()+1).padStart(2,'0');
  reportDate = `${dd}-${mm}-${t.getFullYear()}`;
}
function formatDate(ddmmyyyy) {
  const [dd,mm,yyyy] = ddmmyyyy.split('-');
  const d = new Date(`${yyyy}-${mm}-${dd}`);
  if (isNaN(d)) return ddmmyyyy;
  return d.toLocaleDateString('en-IN', {
    weekday:'long', day:'numeric', month:'long', year:'numeric',
    timeZone:'Asia/Kolkata'
  });
}
document.getElementById('currentDate').textContent = formatDate(reportDate);

/* ────────────────────────────────────────────
    AVATAR GENERATOR
──────────────────────────────────────────── */
const PALETTE = [
  { grad:'linear-gradient(135deg,#f59e0b,#f97316)', strip:'#f59e0b' },
  { grad:'linear-gradient(135deg,#3b82f6,#8b5cf6)', strip:'#3b82f6' },
  { grad:'linear-gradient(135deg,#06b6d4,#3b82f6)', strip:'#06b6d4' },
  { grad:'linear-gradient(135deg,#10b981,#06b6d4)', strip:'#10b981' },
  { grad:'linear-gradient(135deg,#8b5cf6,#ec4899)', strip:'#8b5cf6' }
];
function nameHash(name) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (Math.imul(31, h) + name.charCodeAt(i)) | 0;
  return Math.abs(h) % PALETTE.length;
}
function getPalette(name) { return PALETTE[nameHash(name)] }

/* ────────────────────────────────────────────
    PARSING METHODS
──────────────────────────────────────────── */
function parseTasks(str) {
  if (!str) return [];
  return str.split('\n').map(s => s.trim()).filter(Boolean);
}

function parsePending(str) {
  if (!str) return [];
  return str.split('\n').map(line => {
    const trimmed = line.trim();
    if (!trimmed) return null;

    const lastDashMatch = trimmed.match(/[—–-](?=[^—–-]*$)/);

    if (!lastDashMatch) return { name: trimmed, status: getStatusConfig('') };

    const index = lastDashMatch.index;
    const name = trimmed.slice(0, index).trim();
    const status = getStatusConfig(trimmed.slice(index + 1).trim());

    if (!name) return null;
    return { name, status };
  }).filter(Boolean);
}

/* ────────────────────────────────────────────
    MERGE USER SUBMISSIONS
──────────────────────────────────────────── */
function mergeByUser(rows) {
  const map = new Map();

  rows.forEach(row => {
    const key = (row.user || '').toLowerCase().trim();
    if (!key) return;

    if (!map.has(key)) {
      map.set(key, {
        user:    row.user,
        date:    row.date,
        tasks:   parseTasks(row.tasks),
        pending: parsePending(row.pending),
        notes:   [(row.notes||'').trim()].filter(Boolean),
        submissionCount: 1,
      });
    } else {
      const merged = map.get(key);
      merged.submissionCount++;
      merged.date = row.date;

      const existingTaskKeys = new Set(merged.tasks.map(t => t.toLowerCase()));
      parseTasks(row.tasks).forEach(t => {
        if (!existingTaskKeys.has(t.toLowerCase())) {
          merged.tasks.push(t);
          existingTaskKeys.add(t.toLowerCase());
        }
      });

      const pendingByName = new Map(merged.pending.map(p => [p.name.toLowerCase(), p]));
      parsePending(row.pending).forEach(p => {
        pendingByName.set(p.name.toLowerCase(), p);
      });
      merged.pending = [...pendingByName.values()];

      const note = (row.notes||'').trim();
      if (note && !merged.notes.includes(note)) merged.notes.push(note);
    }
  });

  return [...map.values()].map(m => ({
    user:          m.user,
    date:          m.date,
    tasks:         m.tasks.join('\n'),
    pending:       m.pending.map(p => `${p.name} - ${p.status.label}`).join('\n'),
    notes:         m.notes.join(' · '),
    submissionCount: m.submissionCount,
  }));
}

function escHTML(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/* ────────────────────────────────────────────
    CARD COMPONENT COMPILER
──────────────────────────────────────────── */
function buildCard(row, idx) {
  const tasks   = parseTasks(row.tasks);
  const pending = parsePending(row.pending);
  const notes   = (row.notes || '').trim();
  const pal     = getPalette(row.user);
  const team    = getTeamName(row.user);

  const blockingCount  = pending.filter(p => p.status.isBlocking).length;
  const escalatedCount = pending.filter(p => p.status.isEscalated).length;

  const tasksHTML = tasks.length
    ? tasks.map(t => `<div class="task-item"><i class="fa-solid fa-circle-check"></i><span>${escHTML(t)}</span></div>`).join('')
    : `<p class="empty-inline">No tasks logged</p>`;

  const pendingHTML = pending.length
    ? pending.map(p => `
        <div class="upload-row" title="${escHTML(p.name)}">
          <i class="fa-solid fa-database" style="color:var(--cyan);font-size:11px;flex-shrink:0"></i>
          <span class="upload-name">${escHTML(p.name)}</span>
          <span class="pill" style="${p.status.styles}"><span class="pill-dot"></span>${p.status.label}</span>
        </div>`).join('')
    : `<p class="empty-inline">No uploads tracked</p>`;

  let badgesHTML = '';
  if (escalatedCount) badgesHTML += `<span class="pill" style="background:rgba(239,68,68,0.14); color:#f87171; border:1px solid rgba(239,68,68,0.28); font-size:10px"><span class="pill-dot"></span>${escalatedCount} Escalated</span>`;
  if (blockingCount)  badgesHTML += `<span class="pill" style="background:rgba(249,115,22,0.14); color:#fb923c; border:1px solid rgba(249,115,22,0.28); font-size:10px"><span class="pill-dot"></span>${blockingCount} Blocking</span>`;

  const resubBadge = (row.submissionCount > 1)
    ? `<span style="background:rgba(99,102,241,0.14);color:#a5b4fc;border:1px solid rgba(99,102,241,0.28);font-size:10px;font-weight:600;padding:2px 7px;border-radius:50px;display:inline-flex;align-items:center;gap:4px"><i class="fa-solid fa-code-merge" style="font-size:9px"></i>${row.submissionCount} submissions</span>`
    : '';

  return `
    <div class="member-card">
      <div class="card-accent" style="background:${pal.strip}"></div>
      <div class="card-body">
        <div class="member-hdr">
          <div class="member-avatar" style="background:${pal.grad}">${escHTML(row.user.charAt(0).toUpperCase())}</div>
          <div style="min-width:0">
            <div class="member-name">
              ${escHTML(row.user)}
              <span style="font-size:10px; font-weight:500; color:var(--text3); margin-left:4px; border:1px solid var(--border2); padding: 1px 5px; border-radius:4px; background:var(--bg2)">${team}</span>
            </div>
            <div class="member-date">${formatDate(row.date)}</div>
          </div>
          <div class="member-hdr-right" style="gap:5px;flex-wrap:wrap;margin-left:auto">
            ${resubBadge}
            ${badgesHTML}
          </div>
        </div>

        <div class="section">
          <div class="section-label">
            <i class="fa-solid fa-bolt" style="color:var(--accent2)"></i> Today's tasks
            <span style="margin-left:auto;background:var(--bg2);border:1px solid var(--border2);border-radius:50px;padding:1px 7px;font-size:10px;color:var(--text3)">${tasks.length}</span>
          </div>
          <div class="task-list">${tasksHTML}</div>
        </div>

        <div class="divider"></div>

        <div class="section">
          <div class="section-label">
            <i class="fa-solid fa-cloud-arrow-up" style="color:var(--cyan)"></i> Pending uploads
            <span style="margin-left:auto;background:var(--bg2);border:1px solid var(--border2);border-radius:50px;padding:1px 7px;font-size:10px;color:var(--text3)">${pending.length}</span>
          </div>
          <div class="upload-list">${pendingHTML}</div>
        </div>

        ${notes ? `
        <div class="divider"></div>
        <div class="section">
          <div class="section-label"><i class="fa-solid fa-note-sticky" style="color:var(--purple)"></i> Notes</div>
          <div class="notes-block">${escHTML(notes)}</div>
        </div>` : ''}
      </div>
    </div>`;
}

/* ────────────────────────────────────────────
    RUNTIME DATA ENGINE & FILTERS
──────────────────────────────────────────── */
let allData      = []; 
let activeFilter = 'all';
let activeTeam   = 'all';
let searchQuery  = '';

function setupDynamicFiltersUI() {
  const statusMap = new Map();
  const teamSet = new Set();

  allData.forEach(row => {
    teamSet.add(getTeamName(row.user));
    parsePending(row.pending).forEach(p => {
      statusMap.set(p.status.key, p.status);
    });
  });

  const chipsWrap = document.getElementById('statusChipsWrap');
  let chipsHTML = `<button class="filter-chip ${activeFilter === 'all' ? 'active' : ''}" data-filter="all"><span class="filter-dot"></span> All Statuses</button>`;

  statusMap.forEach(status => {
    const chipStyle = status.styles.replace(/background:[^;]*;\s*/, '');
    chipsHTML += `
      <button class="filter-chip ${activeFilter === status.key ? 'active' : ''}" data-filter="${status.key}" style="${chipStyle}">
        <span class="filter-dot" style="background:currentColor"></span> ${status.label}
      </button>`;
  });
  chipsWrap.innerHTML = chipsHTML;

  document.querySelectorAll('.filter-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      document.querySelectorAll('.filter-chip').forEach(c => c.classList.remove('active'));
      chip.classList.add('active');
      activeFilter = chip.dataset.filter;
      renderAll();
    });
  });

  const teamSelect = document.getElementById('teamFilter');
  let teamHTML = '<option value="all">All Teams</option>';
  [...teamSet].sort().forEach(t => {
    teamHTML += `<option value="${escHTML(t)}">${escHTML(t)}</option>`;
  });
  teamSelect.innerHTML = teamHTML;
  teamSelect.value = activeTeam;
}

function renderAll() {
  const grid = document.getElementById('cardsGrid');

  const filtered = allData.filter(row => {
    const tasks   = parseTasks(row.tasks);
    const pending = parsePending(row.pending);
    const userLo  = (row.user||'').toLowerCase();
    const searchLo = searchQuery.toLowerCase();

    if (activeTeam !== 'all' && getTeamName(row.user) !== activeTeam) return false;

    if (searchQuery) {
      const match = userLo.includes(searchLo) || 
                    tasks.some(t => t.toLowerCase().includes(searchLo)) ||
                    pending.some(p => p.name.toLowerCase().includes(searchLo));
      if (!match) return false;
    }

    if (activeFilter !== 'all') {
      return pending.some(p => p.status.key === activeFilter);
    }
    return true;
  });

  if (filtered.length === 0) {
    grid.innerHTML = `<div class="no-results" style="grid-column:1/-1"><i class="fa-solid fa-magnifying-glass"></i>No members match the dynamic filters applied.</div>`;
    return;
  }

  grid.innerHTML = filtered.map((row, i) => buildCard(row, i)).join('');

  const cards = grid.querySelectorAll('.member-card');
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      cards.forEach((el, i) => {
        el.style.transitionDelay = (0.15 + i * 0.1) + 's';
        el.classList.add('is-visible');
      });
    });
  });
}

function renderSummary(mergedRows, totalRaw) {
  let totalTasks = 0, totalPendingUploads = 0;

  mergedRows.forEach(row => {
    const tasks = parseTasks(row.tasks);
    const pending = parsePending(row.pending);
    totalTasks += tasks.length;
    totalPendingUploads += pending.length;
  });

  document.getElementById('statMembers').textContent = mergedRows.length;
  document.getElementById('statTasks').textContent   = totalTasks;
  document.getElementById('statPending').textContent = totalPendingUploads;

  document.getElementById('summaryBar').style.display = 'grid';
  document.getElementById('filterBar').style.display  = 'flex';

  // Force the browser to paint the "hidden" state at least once before
  // switching to "visible" — otherwise the two style changes can get
  // batched together and the transition never appears to run.
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      document.querySelectorAll('.stat-tile').forEach((el, i) => {
        el.style.transitionDelay = (0.15 + i * 0.18) + 's';
        el.classList.add('is-visible');
      });
    });
  });
}

/* ────────────────────────────────────────────
    INIT PROCESS
──────────────────────────────────────────── */
function loadData() {
  const grid = document.getElementById('cardsGrid');
  const rawRows = Array.isArray(RAW_DATA) && RAW_DATA.length > 0 ? RAW_DATA : [];

  if (rawRows.length === 0) {
    grid.innerHTML = `<div class="state-box" style="grid-column:1/-1"><i class="fa-solid fa-inbox"></i><p>No updates submitted today yet.</p></div>`;
    return;
  }

  allData  = mergeByUser(rawRows);

  setupDynamicFiltersUI();
  renderSummary(allData, rawRows.length);
  renderAll();
}

document.getElementById('teamFilter').addEventListener('change', e => {
  activeTeam = e.target.value;
  renderAll();
});

document.getElementById('searchInput').addEventListener('input', e => {
  searchQuery = e.target.value;
  renderAll();
});

loadData();
</script>
</body>
